import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import TrustBadge from '../components/TrustBadge';
import QRCodeModal from '../components/QRCodeModal';
import './CampaignDetail.css';

const CATEGORY_EMOJI = {
  Medical: '🏥', Education: '📚', Social: '🤝',
  Environment: '🌿', 'Animal Welfare': '🐾',
  'Disaster Relief': '⛑️', Other: '💡'
};

const PRESET_AMOUNTS = [100, 500, 1000, 2500, 5000];
const MONTHLY_AMOUNTS = [100, 200, 500];

const timeAgo = (dateStr) => {
  const diff = Date.now() - new Date(dateStr).getTime();
  const mins = Math.floor(diff / 60000);
  if (mins < 1) return 'just now';
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h ago`;
  const days = Math.floor(hrs / 24);
  if (days < 30) return `${days}d ago`;
  return new Date(dateStr).toLocaleDateString('en-IN', { month: 'short', day: 'numeric' });
};

// ─── Inline SVG Donut Chart ───────────────────────────────────────────────────
const DonutChart = ({ spent, raised }) => {
  const pct = raised > 0 ? Math.min((spent / raised) * 100, 100) : 0;
  const r = 50, cx = 60, cy = 60;
  const circumference = 2 * Math.PI * r;
  const strokeDash = (pct / 100) * circumference;

  return (
    <svg viewBox="0 0 120 120" width="120" height="120" className="donut-svg">
      <circle cx={cx} cy={cy} r={r} fill="none" stroke="#e2e8f0" strokeWidth="14" />
      <circle
        cx={cx} cy={cy} r={r} fill="none"
        stroke="#1a56db" strokeWidth="14"
        strokeDasharray={`${strokeDash} ${circumference - strokeDash}`}
        strokeLinecap="round"
        transform={`rotate(-90 ${cx} ${cy})`}
      />
      <text x={cx} y={cy - 6} textAnchor="middle" fontSize="13" fontWeight="700" fill="#1e293b">{Math.round(pct)}%</text>
      <text x={cx} y={cy + 10} textAnchor="middle" fontSize="8" fill="#64748b">Spent</text>
    </svg>
  );
};

const CampaignDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user, isAuthenticated } = useAuth();

  const [campaign, setCampaign] = useState(null);
  const [donations, setDonations] = useState([]);
  const [updates, setUpdates] = useState([]);
  const [comments, setComments] = useState([]);
  const [fundUsages, setFundUsages] = useState([]);
  const [fundStats, setFundStats] = useState({ totalSpent: 0, totalRaised: 0, remaining: 0 });
  const [supportCampaigns, setSupportCampaigns] = useState([]);

  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [activeTab, setActiveTab] = useState('about');

  // Donation state
  const [donateAmount, setDonateAmount] = useState('');
  const [donateError, setDonateError] = useState('');
  const [donateLoading, setDonateLoading] = useState(false);
  const [donateSuccess, setDonateSuccess] = useState('');
  const [donorMessage, setDonorMessage] = useState('');
  const [isMonthly, setIsMonthly] = useState(false);
  const [selectedMonthlyAmt, setSelectedMonthlyAmt] = useState('');

  // Comments
  const [commentText, setCommentText] = useState('');
  const [commentLoading, setCommentLoading] = useState(false);
  const [commentError, setCommentError] = useState('');

  // Fund usage form (creator)
  const [showUsageForm, setShowUsageForm] = useState(false);
  const [usageForm, setUsageForm] = useState({ title: '', amount: '', receiptImage: '', description: '' });
  const [usageLoading, setUsageLoading] = useState(false);
  const [usageError, setUsageError] = useState('');

  // Updates form (creator)
  const [showUpdateForm, setShowUpdateForm] = useState(false);
  const [updateForm, setUpdateForm] = useState({ title: '', content: '', image: '' });
  const [updateFormLoading, setUpdateFormLoading] = useState(false);
  const [updateFormError, setUpdateFormError] = useState('');

  // Support campaign form
  const [showSupportForm, setShowSupportForm] = useState(false);
  const [supportFormData, setSupportFormData] = useState({ title: '', goal: '' });
  const [supportFormLoading, setSupportFormLoading] = useState(false);
  const [supportFormError, setSupportFormError] = useState('');
  const [supportFormSuccess, setSupportFormSuccess] = useState('');
  const [createdSupportId, setCreatedSupportId] = useState(null);

  // QR modal
  const [showQR, setShowQR] = useState(false);

  const fetchCampaign = useCallback(async () => {
    try {
      setLoading(true);
      setError('');
      const { data } = await axios.get(`/api/campaigns/${id}`);
      setCampaign(data.campaign);
    } catch (err) {
      setError(err.response?.status === 404 ? 'Campaign not found.' : err.response?.data?.message || 'Failed to load.');
    } finally {
      setLoading(false);
    }
  }, [id]);

  const fetchDonations = useCallback(async () => {
    try {
      const { data } = await axios.get(`/api/donations/${id}`);
      setDonations(data.donations);
    } catch { /* silent */ }
  }, [id]);

  const fetchUpdates = useCallback(async () => {
    try {
      const { data } = await axios.get(`/api/updates/${id}`);
      setUpdates(data.updates);
    } catch { /* silent */ }
  }, [id]);

  const fetchComments = useCallback(async () => {
    try {
      const { data } = await axios.get(`/api/comments/${id}`);
      setComments(data.comments);
    } catch { /* silent */ }
  }, [id]);

  const fetchFundUsage = useCallback(async () => {
    try {
      const { data } = await axios.get(`/api/fund-usage/${id}`);
      setFundUsages(data.usages);
      setFundStats({ totalSpent: data.totalSpent, totalRaised: data.totalRaised, remaining: data.remaining });
    } catch { /* silent */ }
  }, [id]);

  const fetchSupportCampaigns = useCallback(async () => {
    try {
      const { data } = await axios.get(`/api/support-campaigns/${id}`);
      setSupportCampaigns(data.supportCampaigns);
    } catch { /* silent */ }
  }, [id]);

  useEffect(() => {
    fetchCampaign();
    fetchDonations();
    fetchUpdates();
    fetchComments();
    fetchFundUsage();
    fetchSupportCampaigns();
  }, [fetchCampaign, fetchDonations, fetchUpdates, fetchComments, fetchFundUsage, fetchSupportCampaigns]);

  // ── Check no-usage warning (14 days after first donation) ─────────────────
  const showUsageWarning = (() => {
    if (!campaign || campaign.raised === 0 || fundUsages.length > 0) return false;
    if (donations.length === 0) return false;
    const firstDonation = new Date(donations[donations.length - 1]?.createdAt);
    const daysSince = (Date.now() - firstDonation.getTime()) / (1000 * 60 * 60 * 24);
    return daysSince >= 14;
  })();

  const isCreator = campaign && user && campaign.creator?._id === user._id;

  // ── Track WhatsApp share ──────────────────────────────────────────────────
  const trackShare = useCallback(async () => {
    try { await axios.post(`/api/campaigns/${id}/track-share`); } catch { /* silent */ }
  }, [id]);

  const handleWhatsAppShare = () => {
    const text = encodeURIComponent(`💙 Support "${campaign.title}" on FundIt: ${window.location.href}`);
    window.open(`https://wa.me/?text=${text}`, '_blank', 'noopener,noreferrer');
    trackShare();
    setCampaign((prev) => ({ ...prev, shareCount: (prev.shareCount || 0) + 1 }));
  };

  // ── One-time Donation ─────────────────────────────────────────────────────
  const handleDonate = async () => {
    if (!isAuthenticated()) { navigate('/login'); return; }
    const amount = Number(donateAmount);
    if (!donateAmount || isNaN(amount) || amount < 1) {
      setDonateError('Please enter a valid amount (min ₹1).'); return;
    }
    if (amount > 500000) { setDonateError('Max donation is ₹5,00,000.'); return; }

    try {
      setDonateLoading(true); setDonateError(''); setDonateSuccess('');
      const { data: orderData } = await axios.post('/api/donations/create-order', { amount, campaignId: id });
      const razorpayKey = process.env.REACT_APP_RAZORPAY_KEY || orderData.key;

      if (typeof window.Razorpay === 'undefined') throw new Error('Razorpay failed to load.');

      const options = {
        key: razorpayKey,
        amount: orderData.amount,
        currency: orderData.currency,
        name: 'FundIt',
        description: `Donation to: ${campaign.title}`,
        order_id: orderData.orderId,
        prefill: { name: user.name, email: user.email },
        theme: { color: '#1a56db' },
        handler: async (response) => {
          try {
            await axios.post('/api/donations/record', {
              campaignId: id, amount, paymentId: response.razorpay_payment_id,
              orderId: response.razorpay_order_id,
              message: donorMessage.trim(),
              isRecurring: false
            });
            setDonateSuccess(`🎉 Thank you ${user.name}! ₹${amount.toLocaleString('en-IN')} donated successfully.`);
            setDonateAmount(''); setDonorMessage('');
            fetchCampaign(); fetchDonations();
          } catch {
            setDonateError(`Payment succeeded (${response.razorpay_payment_id}) but recording failed. Contact support.`);
          } finally { setDonateLoading(false); }
        },
        modal: { ondismiss: () => { setDonateLoading(false); setDonateError('Payment cancelled.'); } }
      };
      const rzp = new window.Razorpay(options);
      rzp.on('payment.failed', (r) => { setDonateLoading(false); setDonateError(`Payment failed: ${r.error.description || 'Unknown error.'}`); });
      rzp.open();
    } catch (err) {
      setDonateLoading(false);
      setDonateError(err.response?.data?.message || err.message || 'Failed to initiate payment.');
    }
  };

  // ── Monthly Subscription ──────────────────────────────────────────────────
  const handleSubscribe = async () => {
    if (!isAuthenticated()) { navigate('/login'); return; }
    const amount = Number(selectedMonthlyAmt);
    if (!selectedMonthlyAmt || isNaN(amount) || amount < 1) {
      setDonateError('Please select a monthly amount.'); return;
    }
    try {
      setDonateLoading(true); setDonateError(''); setDonateSuccess('');
      const { data } = await axios.post('/api/donations/create-subscription', { campaignId: id, amount });

      if (data.subscriptionLink) {
        window.open(data.subscriptionLink, '_blank', 'noopener,noreferrer');
      } else if (typeof window.Razorpay !== 'undefined') {
        const options = {
          key: data.key,
          subscription_id: data.subscriptionId,
          name: 'FundIt',
          description: `₹${amount}/month to ${campaign.title}`,
          prefill: { name: user.name, email: user.email },
          theme: { color: '#1a56db' },
          handler: () => {
            setDonateSuccess(`🔄 Monthly donation of ₹${amount}/month set up successfully!`);
            setIsMonthly(false); setSelectedMonthlyAmt('');
          },
          modal: { ondismiss: () => { setDonateLoading(false); } }
        };
        const rzp = new window.Razorpay(options);
        rzp.open();
      }
      setDonateLoading(false);
    } catch (err) {
      setDonateLoading(false);
      setDonateError(err.response?.data?.message || 'Failed to create subscription.');
    }
  };

  // ── Post Comment ──────────────────────────────────────────────────────────
  const handlePostComment = async () => {
    if (!commentText.trim()) return;
    try {
      setCommentLoading(true); setCommentError('');
      await axios.post(`/api/comments/${id}`, { text: commentText.trim() });
      setCommentText('');
      fetchComments();
    } catch (err) {
      setCommentError(err.response?.data?.message || 'Failed to post comment.');
    } finally {
      setCommentLoading(false);
    }
  };

  // ── Post Fund Usage ───────────────────────────────────────────────────────
  const handleUsageSubmit = async (e) => {
    e.preventDefault();
    if (!usageForm.title || !usageForm.amount) { setUsageError('Title and amount are required.'); return; }
    try {
      setUsageLoading(true); setUsageError('');
      await axios.post(`/api/fund-usage/${id}`, { ...usageForm });
      setUsageForm({ title: '', amount: '', receiptImage: '', description: '' });
      setShowUsageForm(false);
      fetchFundUsage();
    } catch (err) {
      setUsageError(err.response?.data?.message || 'Failed to save.');
    } finally {
      setUsageLoading(false);
    }
  };

  // ── Post Update ───────────────────────────────────────────────────────────
  const handleUpdateSubmit = async (e) => {
    e.preventDefault();
    if (!updateForm.title || !updateForm.content) { setUpdateFormError('Title and content are required.'); return; }
    try {
      setUpdateFormLoading(true); setUpdateFormError('');
      await axios.post(`/api/updates/${id}`, { ...updateForm });
      setUpdateForm({ title: '', content: '', image: '' });
      setShowUpdateForm(false);
      fetchUpdates();
    } catch (err) {
      setUpdateFormError(err.response?.data?.message || 'Failed to post update.');
    } finally {
      setUpdateFormLoading(false);
    }
  };

  // ── Create Support Campaign ───────────────────────────────────────────────
  const handleSupportSubmit = async (e) => {
    e.preventDefault();
    if (!supportFormData.title || !supportFormData.goal) { setSupportFormError('Title and goal are required.'); return; }
    try {
      setSupportFormLoading(true); setSupportFormError('');
      const { data } = await axios.post('/api/support-campaigns', {
        parentCampaignId: id,
        title: supportFormData.title,
        goal: Number(supportFormData.goal)
      });
      setSupportFormSuccess('Support campaign created!');
      setCreatedSupportId(data.supportCampaign._id);
      setSupportFormData({ title: '', goal: '' });
      fetchSupportCampaigns();
    } catch (err) {
      setSupportFormError(err.response?.data?.message || 'Failed to create support campaign.');
    } finally {
      setSupportFormLoading(false);
    }
  };

  // ─── Loading / Error ───────────────────────────────────────────────────
  if (loading) return (
    <div className="loading-state" style={{ minHeight: '60vh' }}>
      <div className="spinner spinner-lg" />
      <p style={{ color: 'var(--text-secondary)' }}>Loading campaign...</p>
    </div>
  );

  if (error) return (
    <div className="container" style={{ paddingTop: '4rem', textAlign: 'center' }}>
      <div className="alert alert-error" style={{ maxWidth: '500px', margin: '0 auto 2rem' }}>
        <span>⚠️</span><p>{error}</p>
      </div>
      <Link to="/" className="btn btn-primary" id="btn-back-home">← Back to Campaigns</Link>
    </div>
  );

  const progress = Math.min(Math.round((campaign.raised / campaign.goal) * 100), 100);
  const remaining = Math.max(campaign.goal - campaign.raised, 0);
  const isGoalReached = campaign.raised >= campaign.goal;
  const createdDate = new Date(campaign.createdAt).toLocaleDateString('en-IN', { year: 'numeric', month: 'long', day: 'numeric' });
  const donateAmountNum = Number(donateAmount);

  const TABS = [
    { key: 'about', label: '📄 About' },
    { key: 'updates', label: `📢 Updates${updates.length > 0 ? ` (${updates.length})` : ''}` },
    { key: 'fundusage', label: '💸 Fund Usage' },
    { key: 'comments', label: `💬 Comments${comments.length > 0 ? ` (${comments.length})` : ''}` },
    { key: 'donors', label: `💙 Donors${donations.length > 0 ? ` (${donations.length})` : ''}` },
    { key: 'leaderboard', label: `🏆 Supporters${supportCampaigns.length > 0 ? ` (${supportCampaigns.length})` : ''}` },
  ];

  return (
    <div className="campaign-detail-page">
      {showQR && (
        <QRCodeModal
          campaignUrl={window.location.href}
          campaignTitle={campaign.title}
          onClose={() => setShowQR(false)}
          onShare={trackShare}
        />
      )}

      <div className="container">
        <div className="detail-layout">

          {/* ── Left: Main Content ─────────────────────────────────── */}
          <div className="detail-main">

            {/* Breadcrumb */}
            <div className="breadcrumb" id="detail-breadcrumb">
              <Link to="/">Campaigns</Link>
              <span className="breadcrumb-sep">/</span>
              <span className="badge badge-blue">{campaign.category}</span>
            </div>

            {/* Hero Image */}
            <div className="detail-image-wrapper" id="campaign-hero-image">
              {campaign.imageUrl ? (
                <img
                  src={campaign.imageUrl}
                  alt={campaign.title}
                  className="detail-image"
                  onError={(e) => { e.target.onerror = null; e.target.src = `https://picsum.photos/seed/${id}/900/450`; }}
                />
              ) : (
                <div className="detail-image-placeholder">
                  {CATEGORY_EMOJI[campaign.category] || '💡'}
                </div>
              )}
              {isGoalReached && (
                <div className="goal-reached-badge" id="goal-reached-badge">✅ Goal Reached!</div>
              )}
            </div>

            {/* Info Card */}
            <div className="detail-info-card" id="campaign-info-card">
              <div className="campaign-title-row">
                <h1 className="detail-title" id="campaign-detail-title">{campaign.title}</h1>
                <TrustBadge score={campaign.trustScore || 0} />
              </div>

              <div className="detail-meta">
                <span className="meta-chip">👤 By <strong>&nbsp;{campaign.creator?.name || 'Anonymous'}</strong></span>
                <span className="meta-chip">📅 {createdDate}</span>
                <span className="badge badge-blue">{campaign.category}</span>
                {campaign.shareCount > 0 && (
                  <span className="meta-chip share-count-chip">🔗 Shared {campaign.shareCount} times</span>
                )}
              </div>

              {/* No usage warning */}
              {showUsageWarning && (
                <div className="alert alert-warning" id="no-usage-warning" style={{ marginBottom: '1rem' }}>
                  <span>⚠️</span>
                  <p>Creator hasn't posted any fund usage yet — it's been over 14 days since the first donation.</p>
                </div>
              )}

              {/* ── TABS ── */}
              <div className="detail-tabs" id="campaign-tabs" role="tablist">
                {TABS.map((tab) => (
                  <button
                    key={tab.key}
                    role="tab"
                    aria-selected={activeTab === tab.key}
                    className={`detail-tab-btn ${activeTab === tab.key ? 'detail-tab-btn--active' : ''}`}
                    id={`tab-${tab.key}`}
                    onClick={() => setActiveTab(tab.key)}
                  >
                    {tab.label}
                  </button>
                ))}
              </div>

              {/* ── Tab: About ── */}
              {activeTab === 'about' && (
                <div className="tab-content" id="tab-panel-about">
                  <div className="detail-description" id="campaign-description-text">
                    {campaign.description.split('\n').map((para, i) =>
                      para.trim() ? <p key={i}>{para}</p> : null
                    )}
                  </div>
                  {/* Support Campaign CTA */}
                  <div className="support-campaign-cta" id="support-campaign-cta">
                    <div className="scc-text">
                      <strong>Fundraise for this campaign</strong>
                      <p>Create your own support campaign and help raise even more!</p>
                    </div>
                    {isAuthenticated() ? (
                      <button
                        className="btn btn-secondary btn-sm"
                        id="btn-create-support-campaign"
                        onClick={() => setShowSupportForm(!showSupportForm)}
                      >
                        {showSupportForm ? '✕ Cancel' : '🤝 Support This Campaign'}
                      </button>
                    ) : (
                      <Link to="/login" className="btn btn-secondary btn-sm">🔐 Sign In to Support</Link>
                    )}
                  </div>

                  {showSupportForm && (
                    <form className="support-form" id="support-form" onSubmit={handleSupportSubmit}>
                      <h4>Create Support Campaign</h4>
                      {supportFormError && <div className="alert alert-error"><span>⚠️</span><p>{supportFormError}</p></div>}
                      {supportFormSuccess && (
                        <div className="alert alert-success">
                          <span>🎉</span>
                          <p>{supportFormSuccess} {createdSupportId && (
                            <Link to={`/support/${createdSupportId}`}> → View your support campaign</Link>
                          )}</p>
                        </div>
                      )}
                      <div className="form-group">
                        <label className="form-label">Your Campaign Title *</label>
                        <input
                          className="form-input"
                          placeholder="e.g., Friends raising for Riya's treatment"
                          value={supportFormData.title}
                          onChange={(e) => setSupportFormData((p) => ({ ...p, title: e.target.value }))}
                          required
                        />
                      </div>
                      <div className="form-group">
                        <label className="form-label">Your Goal (₹) *</label>
                        <input
                          className="form-input"
                          type="number"
                          placeholder="e.g., 10000"
                          value={supportFormData.goal}
                          onChange={(e) => setSupportFormData((p) => ({ ...p, goal: e.target.value }))}
                          min={100}
                          required
                        />
                      </div>
                      <button type="submit" className="btn btn-primary" disabled={supportFormLoading} id="btn-support-form-submit">
                        {supportFormLoading ? <><span className="spinner" /> Creating...</> : '🚀 Launch Support Campaign'}
                      </button>
                    </form>
                  )}
                </div>
              )}

              {/* ── Tab: Updates ── */}
              {activeTab === 'updates' && (
                <div className="tab-content" id="tab-panel-updates">
                  {isCreator && (
                    <div className="creator-action-bar">
                      <button className="btn btn-primary btn-sm" id="btn-post-update" onClick={() => setShowUpdateForm(!showUpdateForm)}>
                        {showUpdateForm ? '✕ Cancel' : '+ Post Update'}
                      </button>
                    </div>
                  )}
                  {showUpdateForm && (
                    <form className="update-form" onSubmit={handleUpdateSubmit}>
                      {updateFormError && <div className="alert alert-error"><span>⚠️</span><p>{updateFormError}</p></div>}
                      <div className="form-group">
                        <label className="form-label">Update Title *</label>
                        <input className="form-input" placeholder="e.g., Treatment started!" value={updateForm.title}
                          onChange={(e) => setUpdateForm((p) => ({ ...p, title: e.target.value }))} required />
                      </div>
                      <div className="form-group">
                        <label className="form-label">Content *</label>
                        <textarea className="form-input" rows={4} placeholder="Share what's happening..." value={updateForm.content}
                          onChange={(e) => setUpdateForm((p) => ({ ...p, content: e.target.value }))} required />
                      </div>
                      <div className="form-group">
                        <label className="form-label">Image URL (optional)</label>
                        <input className="form-input" placeholder="https://..." value={updateForm.image}
                          onChange={(e) => setUpdateForm((p) => ({ ...p, image: e.target.value }))} type="url" />
                      </div>
                      <button type="submit" className="btn btn-primary" disabled={updateFormLoading}>
                        {updateFormLoading ? <><span className="spinner" /> Posting...</> : '📢 Post Update'}
                      </button>
                    </form>
                  )}

                  {updates.length === 0 ? (
                    <div className="tab-empty">No updates posted yet.</div>
                  ) : (
                    <div className="updates-timeline" id="updates-timeline">
                      {updates.map((u) => (
                        <div key={u._id} className="update-item">
                          <div className="update-dot" />
                          <div className="update-body">
                            <div className="update-header">
                              <span className="update-title">{u.title}</span>
                              <span className="update-date">{timeAgo(u.createdAt)}</span>
                            </div>
                            <p className="update-content">{u.content}</p>
                            {u.image && (
                              <img src={u.image} alt={u.title} className="update-img"
                                onError={(e) => { e.target.style.display = 'none'; }} />
                            )}
                            <span className="update-author">— {u.postedBy?.name || 'Creator'}</span>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              )}

              {/* ── Tab: Fund Usage ── */}
              {activeTab === 'fundusage' && (
                <div className="tab-content" id="tab-panel-fundusage">
                  {isCreator && (
                    <div className="creator-action-bar">
                      <button className="btn btn-primary btn-sm" id="btn-add-expense" onClick={() => setShowUsageForm(!showUsageForm)}>
                        {showUsageForm ? '✕ Cancel' : '+ Add Expense'}
                      </button>
                    </div>
                  )}

                  {showUsageForm && (
                    <form className="usage-form" onSubmit={handleUsageSubmit}>
                      {usageError && <div className="alert alert-error"><span>⚠️</span><p>{usageError}</p></div>}
                      <div className="form-group">
                        <label className="form-label">Expense Title *</label>
                        <input className="form-input" placeholder="e.g., Hospital admission fee" value={usageForm.title}
                          onChange={(e) => setUsageForm((p) => ({ ...p, title: e.target.value }))} required />
                      </div>
                      <div className="form-group">
                        <label className="form-label">Amount (₹) *</label>
                        <input className="form-input" type="number" placeholder="e.g., 25000" value={usageForm.amount}
                          onChange={(e) => setUsageForm((p) => ({ ...p, amount: e.target.value }))} min={1} required />
                      </div>
                      <div className="form-group">
                        <label className="form-label">Receipt Image URL (optional)</label>
                        <input className="form-input" type="url" placeholder="https://..." value={usageForm.receiptImage}
                          onChange={(e) => setUsageForm((p) => ({ ...p, receiptImage: e.target.value }))} />
                      </div>
                      <div className="form-group">
                        <label className="form-label">Description (optional)</label>
                        <textarea className="form-input" rows={2} placeholder="Brief note..." value={usageForm.description}
                          onChange={(e) => setUsageForm((p) => ({ ...p, description: e.target.value }))} />
                      </div>
                      <button type="submit" className="btn btn-primary" disabled={usageLoading}>
                        {usageLoading ? <><span className="spinner" /> Saving...</> : '💸 Save Expense'}
                      </button>
                    </form>
                  )}

                  {/* Donut Chart Summary */}
                  <div className="fund-usage-summary" id="fund-usage-summary">
                    <DonutChart spent={fundStats.totalSpent} raised={fundStats.totalRaised} />
                    <div className="fund-stats-grid">
                      <div className="fund-stat">
                        <div className="fund-stat-val" style={{ color: '#1a56db' }}>
                          ₹{fundStats.totalRaised.toLocaleString('en-IN')}
                        </div>
                        <div className="fund-stat-label">Total Raised</div>
                      </div>
                      <div className="fund-stat">
                        <div className="fund-stat-val" style={{ color: '#ef4444' }}>
                          ₹{fundStats.totalSpent.toLocaleString('en-IN')}
                        </div>
                        <div className="fund-stat-label">Total Spent</div>
                      </div>
                      <div className="fund-stat">
                        <div className="fund-stat-val" style={{ color: '#22c55e' }}>
                          ₹{fundStats.remaining.toLocaleString('en-IN')}
                        </div>
                        <div className="fund-stat-label">Remaining</div>
                      </div>
                    </div>
                  </div>

                  {fundUsages.length === 0 ? (
                    <div className="tab-empty">No fund usage posted yet.</div>
                  ) : (
                    <div className="fund-usage-list" id="fund-usage-list">
                      {fundUsages.map((fu) => (
                        <div key={fu._id} className="fund-usage-item">
                          <div className="fui-left">
                            {fu.receiptImage ? (
                              <img src={fu.receiptImage} alt="receipt" className="fui-receipt"
                                onError={(e) => { e.target.style.display = 'none'; }} />
                            ) : (
                              <div className="fui-receipt-placeholder">🧾</div>
                            )}
                          </div>
                          <div className="fui-body">
                            <div className="fui-title">{fu.title}</div>
                            {fu.description && <div className="fui-desc">{fu.description}</div>}
                            <div className="fui-date">{new Date(fu.date).toLocaleDateString('en-IN', { month: 'short', day: 'numeric', year: 'numeric' })}</div>
                          </div>
                          <div className="fui-amount">₹{fu.amount.toLocaleString('en-IN')}</div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              )}

              {/* ── Tab: Comments ── */}
              {activeTab === 'comments' && (
                <div className="tab-content" id="tab-panel-comments">
                  {isAuthenticated() ? (
                    <div className="comment-form" id="comment-form">
                      {commentError && <div className="alert alert-error" style={{ marginBottom: '0.75rem' }}><span>⚠️</span><p>{commentError}</p></div>}
                      <textarea
                        id="comment-input"
                        className="form-input"
                        rows={3}
                        placeholder="Ask a question or leave a message for the campaign creator..."
                        value={commentText}
                        onChange={(e) => setCommentText(e.target.value)}
                        maxLength={500}
                      />
                      <div className="comment-form-footer">
                        <span className="char-count">{commentText.length}/500</span>
                        <button
                          className="btn btn-primary btn-sm"
                          id="btn-post-comment"
                          onClick={handlePostComment}
                          disabled={commentLoading || !commentText.trim()}
                        >
                          {commentLoading ? <><span className="spinner" /> Posting...</> : '💬 Post Comment'}
                        </button>
                      </div>
                    </div>
                  ) : (
                    <div className="tab-auth-prompt">
                      <Link to="/login" className="btn btn-primary btn-sm">🔐 Sign In to Comment</Link>
                    </div>
                  )}

                  {comments.length === 0 ? (
                    <div className="tab-empty">No comments yet. Be the first!</div>
                  ) : (
                    <div className="comments-list" id="comments-list">
                      {comments.map((c) => (
                        <div key={c._id} className="comment-item">
                          <div className="comment-avatar">
                            {(c.user?.name || 'A').charAt(0).toUpperCase()}
                          </div>
                          <div className="comment-body">
                            <div className="comment-author">{c.user?.name || 'Anonymous'}</div>
                            <p className="comment-text">{c.text}</p>
                            <div className="comment-date">{timeAgo(c.createdAt)}</div>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              )}

              {/* ── Tab: Donors ── */}
              {activeTab === 'donors' && (
                <div className="tab-content" id="tab-panel-donors">
                  {donations.length === 0 ? (
                    <div className="tab-empty">🌟 Be the first to support this campaign!</div>
                  ) : (
                    <div className="donors-list" id="donors-list">
                      {donations.map((d) => (
                        <div key={d._id} className="donor-row">
                          <div className="donor-avatar">
                            {(d.donor?.name || 'A').charAt(0).toUpperCase()}
                          </div>
                          <div className="donor-info">
                            <div className="donor-name">
                              {d.donor?.name || 'Anonymous'}
                              {d.isRecurring && <span className="monthly-badge">Monthly Supporter 🔄</span>}
                            </div>
                            {d.message && <div className="donor-message">"{d.message}"</div>}
                            <div className="donor-date">{timeAgo(d.createdAt)}</div>
                          </div>
                          <div className="donor-amount">₹{d.amount.toLocaleString('en-IN')}</div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              )}

              {/* ── Tab: Leaderboard ── */}
              {activeTab === 'leaderboard' && (
                <div className="tab-content" id="tab-panel-leaderboard">
                  <p className="leaderboard-desc">Top fundraisers raising money for this campaign</p>
                  {supportCampaigns.length === 0 ? (
                    <div className="tab-empty">No support campaigns yet. <button className="link-btn" onClick={() => setActiveTab('about')}>Create one →</button></div>
                  ) : (
                    <div className="leaderboard-list" id="leaderboard-list">
                      {supportCampaigns.map((sc, i) => (
                        <div key={sc._id} className="leaderboard-row" id={`leaderboard-row-${i + 1}`}>
                          <div className={`lb-rank ${i === 0 ? 'rank-gold' : i === 1 ? 'rank-silver' : i === 2 ? 'rank-bronze' : ''}`}>
                            {i === 0 ? '🥇' : i === 1 ? '🥈' : i === 2 ? '🥉' : `#${i + 1}`}
                          </div>
                          <div className="lb-avatar">
                            {(sc.creator?.name || 'A').charAt(0).toUpperCase()}
                          </div>
                          <div className="lb-info">
                            <Link to={`/support/${sc._id}`} className="lb-title">{sc.title}</Link>
                            <div className="lb-creator">{sc.creator?.name || 'Supporter'}</div>
                          </div>
                          <div className="lb-raised">
                            <div className="lb-raised-val">₹{sc.raised.toLocaleString('en-IN')}</div>
                            <div className="lb-raised-goal">of ₹{sc.goal.toLocaleString('en-IN')}</div>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              )}

            </div>
          </div>

          {/* ── Right: Sticky Sidebar ─────────────────────────────────── */}
          <div className="donation-sidebar" id="donation-sidebar">

            {/* Progress Card */}
            <div className="progress-card" id="progress-card">
              <div className="raised-amount-display" id="raised-display">
                ₹{campaign.raised.toLocaleString('en-IN')}
              </div>
              <div className="raised-of-goal">raised of ₹{campaign.goal.toLocaleString('en-IN')} goal</div>

              <div className="progress-bar-wrapper" style={{ height: '10px' }}>
                <div
                  className="progress-bar-fill" style={{ width: `${progress}%` }}
                  id="campaign-progress-bar" role="progressbar"
                  aria-valuenow={progress} aria-valuemin="0" aria-valuemax="100"
                />
              </div>

              <div className="progress-stats-row" id="progress-stats">
                <div className="p-stat">
                  <span className="p-stat-val" style={{ color: 'var(--primary)' }}>{progress}%</span>
                  <span className="p-stat-label">Funded</span>
                </div>
                <div className="p-stat">
                  <span className="p-stat-val">{donations.length}</span>
                  <span className="p-stat-label">Donors</span>
                </div>
                <div className="p-stat">
                  <span className="p-stat-val" style={{ fontSize: '0.85rem' }}>₹{remaining.toLocaleString('en-IN')}</span>
                  <span className="p-stat-label">Left</span>
                </div>
              </div>
            </div>

            {/* Donate Card */}
            <div className="donate-form-card" id="donate-form-card">
              {/* Monthly toggle */}
              <div className="monthly-toggle-row" id="monthly-toggle-row">
                <button
                  className={`toggle-btn ${!isMonthly ? 'toggle-btn--active' : ''}`}
                  id="btn-one-time"
                  onClick={() => { setIsMonthly(false); setDonateError(''); setDonateSuccess(''); }}
                >
                  One-time
                </button>
                <button
                  className={`toggle-btn ${isMonthly ? 'toggle-btn--active' : ''}`}
                  id="btn-monthly"
                  onClick={() => { setIsMonthly(true); setDonateError(''); setDonateSuccess(''); }}
                >
                  🔄 Monthly
                </button>
              </div>

              <h3 className="donate-form-title">{isMonthly ? '🔄 Donate Monthly' : '💙 Make a Donation'}</h3>

              {donateSuccess && <div className="alert alert-success" id="donate-success" role="alert"><span>🎉</span><p>{donateSuccess}</p></div>}
              {donateError && <div className="alert alert-error" id="donate-error" role="alert"><span>⚠️</span><p>{donateError}</p></div>}

              {!isAuthenticated() ? (
                <>
                  <p style={{ fontSize: '0.85rem', color: 'var(--text-secondary)', marginBottom: '1rem' }}>Sign in to support this campaign.</p>
                  <Link to="/login" className="login-to-donate-btn" id="btn-login-to-donate">🔐 Sign In to Donate</Link>
                </>
              ) : isMonthly ? (
                <>
                  <p className="monthly-desc">Choose a monthly amount:</p>
                  <div className="monthly-preset-grid" id="monthly-preset-grid">
                    {MONTHLY_AMOUNTS.map((amt) => (
                      <button
                        key={amt}
                        id={`monthly-preset-${amt}`}
                        className={`preset-btn ${selectedMonthlyAmt === String(amt) ? 'preset-btn-active' : ''}`}
                        onClick={() => { setSelectedMonthlyAmt(String(amt)); setDonateError(''); }}
                      >
                        ₹{amt}/mo
                      </button>
                    ))}
                  </div>
                  <button
                    className="donate-cta-btn"
                    id="btn-subscribe"
                    onClick={handleSubscribe}
                    disabled={donateLoading || !selectedMonthlyAmt}
                    style={{ marginTop: '0.75rem' }}
                  >
                    {donateLoading ? <><span className="spinner" /> Processing...</> : `🔄 Subscribe ₹${selectedMonthlyAmt || '?'}/month`}
                  </button>
                  <div className="secure-badge">🔒 Cancel anytime · Powered by Razorpay</div>
                </>
              ) : (
                <>
                  <div className="preset-grid" id="preset-amounts">
                    {PRESET_AMOUNTS.map((amt) => (
                      <button
                        key={amt}
                        id={`preset-${amt}`}
                        className={`preset-btn ${donateAmount === String(amt) ? 'preset-btn-active' : ''}`}
                        onClick={() => { setDonateAmount(String(amt)); setDonateError(''); setDonateSuccess(''); }}
                        type="button"
                      >
                        ₹{amt.toLocaleString('en-IN')}
                      </button>
                    ))}
                  </div>
                  <span className="custom-amount-label">Or enter custom amount</span>
                  <div className="amount-input-wrapper">
                    <span className="amount-prefix">₹</span>
                    <input
                      id="donate-amount-input"
                      type="number"
                      className="amount-input"
                      placeholder="Enter amount"
                      value={donateAmount}
                      onChange={(e) => { setDonateAmount(e.target.value); setDonateError(''); setDonateSuccess(''); }}
                      min={1} max={500000}
                    />
                  </div>

                  {/* Donor message */}
                  <div className="form-group" style={{ marginTop: '0.75rem' }}>
                    <input
                      id="donor-message-input"
                      type="text"
                      className="form-input"
                      placeholder="Leave a message (optional)"
                      value={donorMessage}
                      onChange={(e) => setDonorMessage(e.target.value)}
                      maxLength={300}
                    />
                  </div>

                  {donateAmountNum > 0 && (
                    <div className="donate-summary-row" id="donation-summary">
                      <span>You are donating</span>
                      <strong>₹{donateAmountNum.toLocaleString('en-IN')}</strong>
                    </div>
                  )}

                  <button
                    className="donate-cta-btn"
                    id="btn-donate-now"
                    onClick={handleDonate}
                    disabled={donateLoading || !donateAmount || donateAmountNum < 1}
                  >
                    {donateLoading ? <><span className="spinner" /> Processing...</> : '💚 Donate via Razorpay'}
                  </button>
                  <div className="secure-badge" id="secure-badge">🔒 100% Secure · Powered by Razorpay</div>
                </>
              )}
            </div>

            {/* Share Card */}
            <div className="share-card" id="share-card">
              <p className="share-card-title">📣 Share &amp; Spread the Word</p>
              <div className="share-buttons">
                <button className="share-btn share-wa" id="btn-share-whatsapp" onClick={handleWhatsAppShare}>
                  📱 WhatsApp
                </button>
                <button
                  className="share-btn share-tw"
                  id="btn-share-twitter"
                  onClick={() => window.open(`https://twitter.com/intent/tweet?text=${encodeURIComponent(`Help fund "${campaign.title}" 💙`)}&url=${encodeURIComponent(window.location.href)}`, '_blank', 'noopener,noreferrer')}
                >
                  🐦 Twitter
                </button>
                <button
                  className="share-btn share-copy"
                  id="btn-copy-link"
                  onClick={() => { navigator.clipboard.writeText(window.location.href); alert('Link copied!'); }}
                >
                  🔗 Copy Link
                </button>
                <button
                  className="share-btn share-qr"
                  id="btn-qr-code"
                  onClick={() => setShowQR(true)}
                >
                  📷 QR Code
                </button>
              </div>
              {campaign.shareCount > 0 && (
                <p className="share-count-display" id="share-count-display">
                  🔗 Shared {campaign.shareCount} times
                </p>
              )}
            </div>

          </div>
        </div>
      </div>
    </div>
  );
};

export default CampaignDetail;
